<?php
require_once '../config/Database.php';require_once '../config/auth.php';requerir_login(['admin_hotel','admin']);$db=(new Database())->connect();$idHotel=(int)id_hotel_actual();
$st=$db->prepare("SELECT COUNT(*) total,COALESCE(AVG(r.promedio),0) promedio,SUM(r.mostro_redes) positivas FROM encuesta_respuestas r JOIN encuestas e ON e.id_encuesta=r.id_encuesta WHERE e.id_hotel=?");$st->execute([$idHotel]);$stats=$st->fetch(PDO::FETCH_ASSOC);
$st=$db->prepare("SELECT a.nombre,COUNT(d.id_detalle) respuestas,COALESCE(AVG(d.calificacion),0) promedio FROM encuesta_areas a JOIN encuestas e ON e.id_encuesta=a.id_encuesta LEFT JOIN encuesta_respuesta_detalle d ON d.id_area=a.id_area WHERE e.id_hotel=? GROUP BY a.id_area ORDER BY promedio DESC");$st->execute([$idHotel]);$areas=$st->fetchAll(PDO::FETCH_ASSOC);
$st=$db->prepare("SELECT r.*,e.titulo FROM encuesta_respuestas r JOIN encuestas e ON e.id_encuesta=r.id_encuesta WHERE e.id_hotel=? ORDER BY r.fecha_respuesta DESC LIMIT 200");$st->execute([$idHotel]);$respuestas=$st->fetchAll(PDO::FETCH_ASSOC);
?><!doctype html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Resultados de encuestas</title><link href="https://fonts.googleapis.com/css2?family=Poppins:wght@400;600;700;800&display=swap" rel="stylesheet"><link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css"><style>*{box-sizing:border-box}body{margin:0;background:#f4f7fb;color:#142131;font-family:Poppins}.top{background:#162330;color:#fff;padding:16px 24px;display:flex;justify-content:space-between}.top a{background:#fff;color:#162330;text-decoration:none;padding:10px 14px;border-radius:12px;font-weight:800}.wrap{max-width:1200px;margin:25px auto;padding:0 18px}.head{display:flex;justify-content:space-between;align-items:center;gap:12px}.tabs{display:flex;gap:10px}.tabs a{padding:11px 15px;border-radius:12px;background:#e8eef5;color:#334155;text-decoration:none;font-weight:800}.tabs .active{background:#16a06a;color:#fff}.stats{display:grid;grid-template-columns:repeat(3,1fr);gap:15px;margin:20px 0}.card,.stat{background:white;border:1px solid #e1e9f2;border-radius:18px;box-shadow:0 12px 35px #0f172a0c}.stat{padding:20px}.stat span{color:#64748b;font-size:12px;font-weight:800}.stat strong{display:block;font-size:30px;margin-top:5px}.card{padding:20px;margin-bottom:18px}.area{display:grid;grid-template-columns:1fr 90px 80px;gap:12px;padding:12px;border-bottom:1px solid #edf2f7}.bar{height:9px;background:#e2e8f0;border-radius:999px;margin-top:7px;overflow:hidden}.bar i{display:block;height:100%;background:#16a06a}.table{overflow:auto}table{width:100%;border-collapse:collapse}th,td{text-align:left;padding:12px;border-bottom:1px solid #e8eef5;font-size:13px}th{font-size:11px;text-transform:uppercase;color:#64748b}.stars{color:#f59e0b;font-weight:800}@media(max-width:800px){.stats{grid-template-columns:1fr}.head{flex-direction:column;align-items:flex-start}}</style></head><body><header class="top"><b><i class="fa-solid fa-chart-line"></i> Resultados de encuestas</b><a href="recepcion.php">Volver</a></header><main class="wrap"><div class="head"><div><h1>Dashboard de satisfacción</h1><p>Datos generales asociados a las respuestas.</p></div><div class="tabs"><a href="encuestas.php">Configurar</a><a class="active" href="encuestas_resultados.php">Ver resultados</a></div></div><section class="stats"><div class="stat"><span>Respuestas</span><strong><?=(int)$stats['total']?></strong></div><div class="stat"><span>Promedio general</span><strong><?=number_format((float)$stats['promedio'],2)?> ★</strong></div><div class="stat"><span>Calificaciones positivas</span><strong><?=(int)$stats['positivas']?></strong></div></section><section class="card"><h2>Resultados por área</h2><?php foreach($areas as $a):?><div class="area"><div><b><?=htmlspecialchars($a['nombre'])?></b><div class="bar"><i style="width:<?=min(100,(float)$a['promedio']*20)?>%"></i></div></div><div class="stars"><?=number_format((float)$a['promedio'],2)?> ★</div><small><?=(int)$a['respuestas']?> resp.</small></div><?php endforeach;?></section><section class="card"><h2>Respuestas recientes</h2><div class="table"><table><thead><tr><th>Fecha</th><th>Encuesta</th><th>Cliente</th><th>Promedio</th><th>Comentario</th><th>Redes</th></tr></thead><tbody><?php foreach($respuestas as $r):?><tr><td><?=htmlspecialchars($r['fecha_respuesta'])?></td><td><?=htmlspecialchars($r['titulo'])?></td><td><?=htmlspecialchars($r['nombre_cliente']?:'Anónimo')?></td><td class="stars"><?=number_format((float)$r['promedio'],2)?> ★</td><td><?=htmlspecialchars($r['comentario']?:'-')?></td><td><?=$r['mostro_redes']?'Sí':'No'?></td></tr><?php endforeach;?></tbody></table></div></section></main></body></html>
